SELECT * FROM decision_signal_outcomes

    AND signal_id = #{signalId}
    AND horizon = #{horizon}
    AND engine_version = #{engineVersion}
    AND eval_status = #{evalStatus}
    AND outcome = #{outcome}

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM decision_signal_outcomes

    AND signal_id = #{signalId}
    AND horizon = #{horizon}
    AND eval_status = #{evalStatus}
    AND outcome = #{outcome}

SELECT horizon, outcome, COUNT(*) as count, AVG(return_pct) as avg_return_pct FROM decision_signal_outcomes WHERE eval_status = 'completed'
AND horizon IN #{h}
AND engine_version = #{engineVersion} GROUP BY horizon, outcome
